// Parse CSV helper function
function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];

    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current.trim());
  return result;
}

// Parse CSV content
const lines = csvContent.trim().split('\n');
const headers = parseCSVLine(lines[0]);

const outputItems = [];
for (let i = 1; i < lines.length; i++) {
  const line = lines[i].trim();
  if (line) {
    const values = parseCSVLine(line);
    const ticket = {};
    headers.forEach((header, index) => {
      ticket[header] = values[index] || '';
    });
    outputItems.push({ json: ticket });
  }
}

return outputItems;

const inputItems = $input.all();

const fallbackClassification = {
  urgency: "Low",
  category: "General Inquiry",
  summary: "Ticket could not be classified automatically due to an API error or rate limit.",
  flag_for_review: true
};

function parseClassification(apiResponse, originalTicket) {
  // Check for error
  if (apiResponse.error || apiResponse.statusCode === 429) {
    return fallbackClassification;
  }

  try {
    const aiText = apiResponse.candidates?.[0]?.content?.parts?.[0]?.text;

    if (!aiText || aiText.trim() === '') {
      return fallbackClassification;
    }

    const cleanText = aiText
      .replace(/```json\n?/g, '')
      .replace(/```\n?/g, '')
      .trim();

    const parsed = JSON.parse(cleanText);

    if (
      !parsed.urgency ||
      !parsed.category ||
      !parsed.summary ||
      parsed.flag_for_review === undefined ||
      parsed.flag_for_review === null
    ) {
      return fallbackClassification;
    }

    return {
      urgency: parsed.urgency,
      category: parsed.category,
      summary: parsed.summary,
      flag_for_review: parsed.flag_for_review
    };
  } catch (error) {
    return fallbackClassification;
  }
}

const outputItems = inputItems.map(item => {
  const currentData = item.json;
  const originalTicket = $('Split in Batches').item.json;
  const classification = parseClassification(currentData, originalTicket);

  return {
    json: {
      ticket_id: originalTicket.ticket_id || '',
      created_at: originalTicket.created_at || '',
      customer_name: originalTicket.customer_name || '',
      customer_email: originalTicket.customer_email || '',
      subject: originalTicket.subject || '',
      body: originalTicket.body || '',
      status: originalTicket.status || '',
      urgency: classification.urgency,
      category: classification.category,
      summary: classification.summary,
      flag_for_review: classification.flag_for_review
    }
  };
});

return outputItems;

const ticket = $input.item.json;

const textToCheck = `${ticket.subject || ''} ${ticket.body || ''}`.toLowerCase();

const fraudKeywords = [
  'forged',
  'fake id',
  'fake document',
  'altered document',
  'doctored',
  'tampered',
  'stolen identity',
  'identity theft',
  'impersonat',
  'unauthorized account',
  'someone else using',
  'used without my permission',
  'not mine',
  'identity mismatch',
  'suspicious activity'
];

let fraudDetected = false;
for (const keyword of fraudKeywords) {
  if (textToCheck.includes(keyword)) {
    fraudDetected = true;
    break;
  }
}

if (fraudDetected) {
  ticket.category = 'Fraud Concern';
  ticket.flag_for_review = true;

  const highUrgencyIndicators = [
    'stolen identity',
    'identity theft',
    'impersonat',
    'unauthorized account',
    'someone else using',
    'used without my permission',
    'forged',
    'fake id',
    'tampered'
  ];

  for (const indicator of highUrgencyIndicators) {
    if (textToCheck.includes(indicator)) {
      ticket.urgency = 'High';
      break;
    }
  }
}

return { json: ticket };

function escapeCSV(value) {
  if (value === null || value === undefined) {
    return '';
  }

  const stringValue = String(value);

  if (
    stringValue.includes(',') ||
    stringValue.includes('"') ||
    stringValue.includes('\n') ||
    stringValue.includes('\r')
  ) {
    return '"' + stringValue.replace(/"/g, '""') + '"';
  }

  return stringValue;
}

const inputItem = $input.first().json;
const rows = Array.isArray(inputItem.data) ? inputItem.data : [];

const headers = [
  'ticket_id',
  'created_at',
  'customer_name',
  'customer_email',
  'subject',
  'body',
  'status',
  'urgency',
  'category',
  'summary',
  'flag_for_review'
];

let csvContent = headers.join(',') + '\n';

for (const rowData of rows) {
  const row = headers.map(header => escapeCSV(rowData[header]));
  csvContent += row.join(',') + '\n';
}

return [
  {
    json: {
      csvContent,
      ticketCount: rows.length
    }
  }
];

const csvContent = $input.item.json.csvContent;
const ticketCount = $input.item.json.ticketCount;

const binaryData = Buffer.from(csvContent, 'utf-8');

return {
  json: {
    ticketCount: ticketCount,
    message: `CSV file generated with ${ticketCount} ticket(s)`
  },
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'text/csv',
      fileName: 'classified_tickets.csv'
    }
  }
};
